import type { Question } from "../types";

export const QUESTIONS: Record<string, Question[]> = {
  algoritmos: [
    { id: 1, diff: "basica", text: "O que é um algoritmo?", opts: ["Uma linguagem de programação", "Uma sequência lógica de passos para resolver um problema", "Um tipo de variável", "Um erro de código"], correct: 1, explain: "Um algoritmo é uma sequência finita e ordenada de passos para resolver um problema ou realizar uma tarefa.", wrongFeedback: { 0: "Linguagem de programação (Python, Java...) é a ferramenta usada para implementar um algoritmo, mas não é o algoritmo em si. Um algoritmo pode ser descrito em português mesmo.", 2: "Variável é um espaço de memória para guardar dados — um conceito diferente. Algoritmo é a sequência de passos, não um tipo de dado.", 3: "Erro de código é resultado de uma implementação incorreta. Algoritmo é justamente o plano correto para resolver um problema." } },
    { id: 2, diff: "basica", text: "Qual característica NÃO pertence a um algoritmo?", opts: ["Ser finito", "Ser ambíguo", "Ter entradas e saídas", "Ser eficaz"], correct: 1, explain: "Um algoritmo deve ser preciso e não ambíguo — cada passo deve ter um significado claro e único.", wrongFeedback: { 0: "Finitude é uma característica obrigatória — todo algoritmo deve terminar em algum momento.", 2: "Entradas e saídas fazem parte do modelo IPO (Input-Process-Output), que é fundamental em algoritmos.", 3: "Eficácia (produzir o resultado correto) é esperada de todo algoritmo válido." } },
    { id: 3, diff: "basica", text: "Qual das opções abaixo é um exemplo de algoritmo do cotidiano?", opts: ["Uma música", "Uma receita de bolo", "Uma cor", "Um número"], correct: 1, explain: "Uma receita de bolo é um algoritmo: tem passos ordenados, ingredientes (entradas) e um bolo (saída).", wrongFeedback: { 0: "Uma música tem estrutura, mas não é uma sequência de passos para resolver um problema — é uma expressão artística.", 2: "Uma cor é apenas um dado, não uma sequência de instruções.", 3: "Um número é um valor, não uma sequência de passos com entrada, processamento e saída." } },
    { id: 4, diff: "basica", text: "O que significa dizer que um algoritmo é 'finito'?", opts: ["Que ele é muito pequeno", "Que ele termina após um número limitado de passos", "Que ele só funciona uma vez", "Que ele não aceita entradas"], correct: 1, explain: "Finitude significa que o algoritmo deve terminar em algum momento — não pode rodar para sempre." },
    { id: 5, diff: "basica", text: "Qual é a ordem correta das fases de um algoritmo?", opts: ["Processamento → Entrada → Saída", "Saída → Processamento → Entrada", "Entrada → Processamento → Saída", "Entrada → Saída → Processamento"], correct: 2, explain: "O modelo IPO (Input-Process-Output): primeiro recebemos dados, processamos e depois exibimos o resultado." },
    { id: 6, diff: "basica", text: "Um algoritmo pode ter zero entradas?", opts: ["Não, sempre precisa de entradas", "Sim, alguns algoritmos não precisam de entradas", "Só se tiver zero saídas também", "Apenas em linguagens específicas"], correct: 1, explain: "Sim! Um algoritmo que imprime 'Olá, mundo!' não precisa de nenhuma entrada do usuário." },
    { id: 7, diff: "basica", text: "O que é pseudocódigo?", opts: ["Um código com erros", "Uma linguagem de programação real", "Uma forma de descrever algoritmos em linguagem próxima ao humano", "Um tipo de compilador"], correct: 2, explain: "Pseudocódigo é uma forma estruturada de escrever algoritmos usando linguagem informal, sem sintaxe rígida de uma linguagem real." },
    { id: 8, diff: "intermediaria", text: "Qual das sequências representa um algoritmo correto para fazer café?", opts: ["Beber o café → Colocar a água → Ligar a cafeteira", "Colocar a água → Colocar o pó → Ligar a cafeteira → Beber o café", "Ligar a cafeteira → Colocar o pó → Beber", "Beber → Ligar → Colocar"], correct: 1, explain: "Um algoritmo tem ordem lógica. Primeiro preparamos, depois executamos e por fim colhemos o resultado." },
    { id: 9, diff: "intermediaria", text: "Qual problema existe no algoritmo: 'Some dois números. Se o resultado for grande, pare'?", opts: ["Não tem problema", "O critério 'grande' é ambíguo", "Faltam entradas", "Tem passos demais"], correct: 1, explain: "Ambiguidade: 'grande' não tem definição precisa. Um algoritmo deve ter instruções exatas e sem dupla interpretação." },
    { id: 10, diff: "intermediaria", text: "Para encontrar o maior número em uma lista de 10 elementos, quantas comparações são necessárias no mínimo?", opts: ["5", "9", "10", "100"], correct: 1, explain: "Precisamos comparar cada elemento com o maior atual. Para 10 elementos, fazemos 9 comparações (n-1)." },
    { id: 11, diff: "intermediaria", text: "O que é um fluxograma?", opts: ["Um tipo de variável", "Uma representação visual de um algoritmo usando símbolos", "Um erro de algoritmo", "Uma linguagem de programação"], correct: 1, explain: "Fluxograma é uma representação gráfica de um algoritmo usando símbolos padronizados como retângulos (ações) e losangos (decisões)." },
    { id: 12, diff: "intermediaria", text: "Qual símbolo de fluxograma representa uma decisão (condição)?", opts: ["Retângulo", "Oval", "Losango", "Paralelogramo"], correct: 2, explain: "O losango representa um ponto de decisão no fluxograma, onde o fluxo pode seguir dois ou mais caminhos." },
    { id: 13, diff: "intermediaria", text: "O que é refinamento sucessivo em algoritmos?", opts: ["Corrigir erros de sintaxe", "Detalhar progressivamente os passos de um algoritmo genérico", "Remover passos desnecessários", "Traduzir para código"], correct: 1, explain: "Refinamento sucessivo é a técnica de começar com uma descrição geral e ir detalhando cada passo até chegar ao nível de código." },
    { id: 14, diff: "intermediaria", text: "Qual a diferença entre um algoritmo e um programa?", opts: ["Não há diferença", "Um algoritmo é a solução lógica; o programa é sua implementação em uma linguagem", "Um programa é mais genérico que um algoritmo", "Algoritmos só existem no papel"], correct: 1, explain: "O algoritmo é a ideia/lógica da solução. O programa é essa lógica implementada em uma linguagem de programação específica." },
    { id: 15, diff: "intermediaria", text: "Um algoritmo que nunca termina é chamado de:", opts: ["Algoritmo rápido", "Loop infinito", "Algoritmo paralelo", "Recursão"], correct: 1, explain: "Loop infinito ocorre quando um algoritmo não tem condição de parada adequada e continua executando indefinidamente." },
    { id: 16, diff: "avancada", text: "Qual é a complexidade de um algoritmo que verifica cada elemento de uma lista uma vez?", opts: ["O(1)", "O(log n)", "O(n)", "O(n²)"], correct: 2, explain: "O(n) — complexidade linear. Se a lista dobra de tamanho, o tempo de execução também dobra." },
    { id: 17, diff: "avancada", text: "O que é recursão?", opts: ["Um loop simples", "Quando uma função chama a si mesma", "Um tipo de variável", "Um algoritmo de ordenação"], correct: 1, explain: "Recursão é quando uma função resolve um problema chamando a si mesma com uma versão menor do problema, até atingir um caso base." },
    { id: 18, diff: "avancada", text: "Qual algoritmo de busca requer que a lista esteja ordenada para funcionar eficientemente?", opts: ["Busca linear", "Busca sequencial", "Busca binária", "Busca aleatória"], correct: 2, explain: "A busca binária divide a lista ao meio a cada passo (O(log n)), mas exige que os dados estejam ordenados." },
    { id: 19, diff: "avancada", text: "O que diferencia um algoritmo guloso (greedy) de programação dinâmica?", opts: ["Velocidade de execução", "Greedy faz a melhor escolha local; dinâmica considera subproblemas sobrepostos", "Uso de memória", "Linguagem utilizada"], correct: 1, explain: "Algoritmos gulosos escolhem a melhor opção a cada passo sem revisar. Programação dinâmica resolve subproblemas e armazena resultados para decisões globais ótimas." },
    { id: 20, diff: "avancada", text: "Qual é o caso base obrigatório em qualquer algoritmo recursivo?", opts: ["Uma variável global", "Uma condição que para a recursão sem nova chamada recursiva", "Um loop interno", "Uma entrada do usuário"], correct: 1, explain: "Sem caso base, a recursão seria infinita. O caso base é a condição que resolve o problema diretamente, sem chamar a função novamente." },
    { id: 21, diff: "avancada", text: "O algoritmo Bubble Sort tem qual complexidade no pior caso?", opts: ["O(n)", "O(n log n)", "O(n²)", "O(log n)"], correct: 2, explain: "Bubble Sort compara pares adjacentes repetidamente. No pior caso (lista invertida), faz n*(n-1)/2 comparações — O(n²)." },
  ],
  variaveis: [
    { id: 1, diff: "basica", text: "O que é uma variável em programação?", opts: ["Um erro no código", "Um espaço na memória que guarda um valor", "Um tipo de loop", "Uma função matemática"], correct: 1, explain: "Uma variável é um espaço nomeado na memória que armazena um valor que pode mudar durante a execução.", wrongFeedback: { 0: "Erro de código é um problema na lógica ou sintaxe do programa, não tem relação com variáveis.", 2: "Loop é uma estrutura de repetição (for, while) — diferente de variável, que guarda dados.", 3: "Função matemática é um conceito de matemática. Em programação, funções são blocos de código; variáveis são espaços de armazenamento." } },
    { id: 2, diff: "basica", text: "Qual desses é um tipo de dado primitivo válido?", opts: ["Algoritmo", "Inteiro (int)", "Condicional", "Loop"], correct: 1, explain: "Inteiro (int) é um tipo de dado primitivo que representa números sem casas decimais.", wrongFeedback: { 0: "Algoritmo é uma sequência de passos para resolver um problema, não um tipo de dado.", 2: "Condicional (if/else) é uma estrutura de controle de fluxo, não um tipo de dado.", 3: "Loop (for/while) é uma estrutura de repetição, não um tipo de dado que você armazena em variáveis." } },
    { id: 3, diff: "basica", text: "Qual o tipo mais adequado para guardar a nota de um aluno (ex: 7.5)?", opts: ["int", "bool", "float", "string"], correct: 2, explain: "Float (ponto flutuante) armazena números decimais, ideal para notas como 7.5 ou 9.8.", wrongFeedback: { 0: "int só armazena números inteiros (1, 2, 42). A nota 7.5 teria a parte decimal truncada e viraria 7 — perdendo precisão.", 1: "bool armazena apenas verdadeiro ou falso. Não serve para guardar notas numéricas.", 3: "string armazena texto. Você poderia guardar '7.5' como texto, mas não conseguiria fazer cálculos matemáticos com ela." } },
    { id: 4, diff: "basica", text: "O que armazena uma variável do tipo string?", opts: ["Números inteiros", "Valores verdadeiro/falso", "Texto (sequência de caracteres)", "Números decimais"], correct: 2, explain: "String armazena texto — sequências de caracteres como 'Olá', 'João' ou 'abc123'." },
    { id: 5, diff: "basica", text: "Qual nome de variável é válido?", opts: ["minha variavel", "2nome", "nome_aluno", "nome-aluno"], correct: 2, explain: "nome_aluno é válido. Nomes não podem começar com número nem ter espaços ou hífens." },
    { id: 6, diff: "basica", text: "O tipo booleano (bool) armazena quais valores?", opts: ["0 a 255", "Qualquer número", "Verdadeiro ou Falso", "Letras do alfabeto"], correct: 2, explain: "Boolean armazena apenas dois valores: verdadeiro (true) ou falso (false). Muito usado em condições." },
    { id: 7, diff: "basica", text: "O que é uma constante, diferente de uma variável?", opts: ["Um valor que muda sempre", "Um valor fixo que não pode ser alterado após definido", "Um tipo de loop", "Uma função"], correct: 1, explain: "Constantes têm valor fixo definido uma vez e não podem ser alteradas durante a execução do programa." },
    { id: 8, diff: "basica", text: "Ao declarar uma variável, o que estamos fazendo?", opts: ["Executando o programa", "Reservando espaço na memória com um nome", "Criando uma função", "Fazendo um loop"], correct: 1, explain: "Declarar uma variável reserva um espaço na memória RAM e associa um nome a esse espaço para uso posterior." },
    { id: 9, diff: "intermediaria", text: "Qual é o resultado de: x = 5; x = x + 3?", opts: ["5", "3", "8", "Erro"], correct: 2, explain: "x começa com 5, depois recebe x + 3 = 5 + 3 = 8. A variável é atualizada com o novo valor." },
    { id: 10, diff: "intermediaria", text: "O que é escopo de uma variável?", opts: ["O tamanho da variável", "A região do código onde a variável é acessível", "O tipo da variável", "O nome da variável"], correct: 1, explain: "Escopo define onde a variável pode ser usada. Variáveis locais existem apenas dentro da função onde foram criadas." },
    { id: 11, diff: "intermediaria", text: "Qual tipo de dado é mais adequado para armazenar a idade de uma pessoa?", opts: ["float", "string", "bool", "int"], correct: 3, explain: "Idade é um número inteiro (não tem decimal), então int é o tipo mais adequado." },
    { id: 12, diff: "intermediaria", text: "O que acontece ao somar um int com uma string em linguagens fortemente tipadas?", opts: ["O resultado é uma string", "Ocorre um erro de tipo", "O resultado é um int", "A string é ignorada"], correct: 1, explain: "Em linguagens fortemente tipadas (como Java), somar tipos incompatíveis gera erro de tipo em tempo de compilação ou execução." },
    { id: 13, diff: "intermediaria", text: "O que é uma variável global?", opts: ["Uma variável muito grande", "Uma variável acessível em todo o programa", "Uma variável de tipo float", "Uma variável constante"], correct: 1, explain: "Variável global é declarada fora de qualquer função e pode ser acessada por qualquer parte do programa." },
    { id: 14, diff: "intermediaria", text: "Quantos bytes ocupa tipicamente um int de 32 bits?", opts: ["1 byte", "2 bytes", "4 bytes", "8 bytes"], correct: 2, explain: "Um int de 32 bits ocupa 4 bytes (32 bits ÷ 8 bits/byte = 4 bytes), podendo representar valores de -2³¹ a 2³¹-1." },
    { id: 15, diff: "intermediaria", text: "O que é inicialização de uma variável?", opts: ["Criar o nome da variável", "Atribuir um valor inicial no momento da declaração", "Apagar a variável", "Trocar o tipo da variável"], correct: 1, explain: "Inicializar é dar um valor inicial à variável. Ex: int x = 0. Usar variável não inicializada pode gerar comportamento indefinido." },
    { id: 16, diff: "intermediaria", text: "Qual o valor de y após: x = 10; y = x; x = 20?", opts: ["20", "10", "0", "Erro"], correct: 1, explain: "y recebe o valor de x no momento da atribuição (10). Alterar x depois não afeta y — são espaços de memória independentes." },
    { id: 17, diff: "avancada", text: "O que é overflow em variáveis inteiras?", opts: ["Variável sem nome", "Quando o valor excede o limite máximo do tipo e 'dá a volta'", "Variável com valor negativo", "Divisão por zero"], correct: 1, explain: "Overflow ocorre quando um valor ultrapassa o limite do tipo. Ex: um int8 com max 127 recebendo 128 resulta em -128." },
    { id: 18, diff: "avancada", text: "O que é type casting (conversão de tipo)?", opts: ["Criar uma nova variável", "Converter um valor de um tipo para outro", "Apagar uma variável", "Renomear uma variável"], correct: 1, explain: "Type casting converte um valor entre tipos. Ex: (int) 3.9 resulta em 3 — o decimal é truncado, não arredondado." },
    { id: 19, diff: "avancada", text: "Qual a diferença entre passagem por valor e por referência?", opts: ["Não há diferença", "Por valor copia o dado; por referência passa o endereço de memória", "Por referência é mais lenta", "Por valor usa mais memória"], correct: 1, explain: "Por valor: a função recebe uma cópia — alterações não afetam a original. Por referência: a função acessa o mesmo espaço de memória." },
    { id: 20, diff: "avancada", text: "O que é uma variável estática (static) em funções?", opts: ["Uma constante", "Uma variável que mantém seu valor entre chamadas da função", "Uma variável global", "Uma variável imutável"], correct: 1, explain: "Variável estática dentro de uma função é inicializada apenas uma vez e mantém seu valor entre diferentes chamadas da mesma função." },
    { id: 21, diff: "avancada", text: "Em linguagens de tipagem dinâmica, o que pode acontecer com o tipo de uma variável?", opts: ["Nunca muda", "Pode mudar durante a execução conforme o valor atribuído", "Só muda com cast explícito", "É definido em tempo de compilação"], correct: 1, explain: "Em Python, JS e outras linguagens de tipagem dinâmica, uma variável pode ser int em um momento e string em outro." },
  ],
  entrada_saida: [
    { id: 1, diff: "basica", text: "O que faz a instrução de 'saída' em um programa?", opts: ["Lê dados do usuário", "Exibe informações na tela", "Armazena valores", "Realiza cálculos"], correct: 1, explain: "A instrução de saída (como print ou cout) exibe informações para o usuário na tela ou console.", wrongFeedback: { 0: "Ler dados do usuário é função da instrução de ENTRADA (input), não de saída.", 2: "Armazenar valores é responsabilidade das variáveis, não da instrução de saída.", 3: "Cálculos são feitos nas expressões aritméticas do programa. A saída apenas exibe o resultado já calculado." } },
    { id: 2, diff: "basica", text: "Qual é a função da instrução de 'entrada' (input)?", opts: ["Exibir texto na tela", "Receber dados fornecidos pelo usuário", "Calcular valores", "Armazenar resultados"], correct: 1, explain: "A instrução de entrada permite que o programa receba dados digitados pelo usuário durante a execução.", wrongFeedback: { 0: "Exibir texto na tela é responsabilidade da instrução de SAÍDA (print/cout). Entrada e saída são operações inversas.", 2: "Calcular valores é responsabilidade das expressões e operadores, não da instrução de entrada.", 3: "Armazenar resultados é papel das variáveis. Após receber uma entrada, normalmente armazenamos ela em uma variável." } },
    { id: 3, diff: "basica", text: "Em qual ordem as operações abaixo fazem mais sentido?", opts: ["Exibir resultado → Calcular → Ler dados", "Ler dados → Calcular → Exibir resultado", "Calcular → Ler dados → Exibir", "Exibir → Ler → Calcular"], correct: 1, explain: "O fluxo natural é: entrada de dados → processamento → saída. Modelo IPO: Input, Process, Output." },
    { id: 4, diff: "basica", text: "O que é um dispositivo de entrada?", opts: ["Monitor", "Teclado", "Impressora", "Alto-falante"], correct: 1, explain: "Teclado é um dispositivo de entrada — envia dados para o computador. Monitor, impressora e alto-falante são saída." },
    { id: 5, diff: "basica", text: "O que é um dispositivo de saída?", opts: ["Teclado", "Mouse", "Scanner", "Monitor"], correct: 3, explain: "Monitor é dispositivo de saída — exibe informações geradas pelo computador para o usuário." },
    { id: 6, diff: "basica", text: "Quando um programa pede 'Digite seu nome:', o que ele está fazendo?", opts: ["Processando dados", "Solicitando uma entrada do usuário", "Exibindo um resultado", "Calculando algo"], correct: 1, explain: "Ao exibir uma mensagem pedindo dados, o programa está solicitando entrada — aguardando que o usuário forneça informação." },
    { id: 7, diff: "basica", text: "Qual instrução em Python exibe texto na tela?", opts: ["input()", "scan()", "print()", "read()"], correct: 2, explain: "print() é a função de saída do Python. Ex: print('Olá!') exibe 'Olá!' no console." },
    { id: 8, diff: "basica", text: "Qual instrução em Python lê dados do usuário?", opts: ["print()", "output()", "write()", "input()"], correct: 3, explain: "input() é a função de entrada do Python. Ela pausa o programa e aguarda o usuário digitar algo." },
    { id: 9, diff: "intermediaria", text: "Por que é importante exibir uma mensagem antes de pedir uma entrada?", opts: ["Não é necessário", "Para o usuário saber o que digitar", "Para deixar o código mais rápido", "Por exigência da linguagem"], correct: 1, explain: "Uma mensagem clara (prompt) informa ao usuário o que o programa espera receber, evitando entradas incorretas." },
    { id: 10, diff: "intermediaria", text: "O que acontece se o usuário digitar texto quando o programa espera um número?", opts: ["O programa converte automaticamente", "Pode ocorrer erro de tipo ou conversão incorreta", "O programa ignora a entrada", "O número 0 é usado"], correct: 1, explain: "Sem tratamento adequado, entrada de tipo errado causa erro. Por isso é importante validar e converter entradas." },
    { id: 11, diff: "intermediaria", text: "O que é necessário fazer com o retorno de input() em Python para usar como número?", opts: ["Nada, já é número", "Converter com int() ou float()", "Usar aspas ao redor", "Chamar num()"], correct: 1, explain: "input() sempre retorna string em Python. Para usar como número, precisamos converter: int(input()) ou float(input())." },
    { id: 12, diff: "intermediaria", text: "O que é formatação de saída?", opts: ["Corrigir erros de código", "Controlar como os dados são exibidos (casas decimais, alinhamento etc.)", "Converter tipos de dados", "Ler arquivos"], correct: 1, explain: "Formatação de saída controla a aparência dos dados exibidos, como número de casas decimais, alinhamento e separadores." },
    { id: 13, diff: "intermediaria", text: "Qual é a saída de: print('Resultado:', 3 + 4)?", opts: ["Resultado: 3 + 4", "Resultado: 7", "7", "Erro"], correct: 1, explain: "Python avalia a expressão 3+4=7 antes de imprimir. print() concatena os argumentos com espaço por padrão." },
    { id: 14, diff: "intermediaria", text: "O que é entrada padrão (stdin)?", opts: ["Um arquivo especial", "O canal padrão de entrada de dados, geralmente o teclado", "Um tipo de variável", "Um dispositivo de saída"], correct: 1, explain: "stdin (standard input) é o canal padrão de entrada, normalmente conectado ao teclado no terminal." },
    { id: 15, diff: "intermediaria", text: "O que é saída padrão (stdout)?", opts: ["Um arquivo de log", "O canal padrão de saída, geralmente o terminal/console", "Um tipo de banco de dados", "A memória RAM"], correct: 1, explain: "stdout (standard output) é o canal padrão de saída onde print() e funções similares enviam os dados." },
    { id: 16, diff: "intermediaria", text: "O que significa 'flush' na saída de dados?", opts: ["Apagar a tela", "Forçar a escrita imediata do buffer de saída", "Converter tipo de dado", "Fechar o programa"], correct: 1, explain: "Flush força a escrita imediata dos dados que estão no buffer para o dispositivo de saída, útil em saídas em tempo real." },
    { id: 17, diff: "avancada", text: "O que é leitura de arquivo (file I/O)?", opts: ["Ler dados do teclado", "Ler e escrever dados em arquivos no disco", "Exibir imagens", "Conectar à internet"], correct: 1, explain: "File I/O permite que programas leiam e gravem dados em arquivos persistentes no disco, além da entrada/saída pelo terminal." },
    { id: 18, diff: "avancada", text: "O que é buffer de I/O?", opts: ["Um tipo de variável especial", "Uma área de memória temporária que acumula dados antes de transferi-los", "Um dispositivo físico", "Um tipo de loop"], correct: 1, explain: "Buffer é uma área de memória intermediária que acumula dados para transferência em lotes, aumentando a eficiência de I/O." },
    { id: 19, diff: "avancada", text: "O que é serialização de dados?", opts: ["Ordenar dados alfabeticamente", "Converter estruturas de dados em formato transmissível (como JSON ou binário)", "Apagar dados duplicados", "Comprimir arquivos"], correct: 1, explain: "Serialização converte objetos/estruturas complexas em formato linear (JSON, XML, binário) para armazenamento ou transmissão." },
    { id: 20, diff: "avancada", text: "O que é stderr?", opts: ["Um tipo de variável", "O canal padrão para mensagens de erro, separado do stdout", "Um arquivo de configuração", "Uma função de leitura"], correct: 1, explain: "stderr (standard error) é o canal dedicado a mensagens de erro. Separar erros da saída normal facilita diagnóstico e redirecionamento." },
    { id: 21, diff: "avancada", text: "Qual a vantagem de usar entrada/saída assíncrona?", opts: ["Código mais simples", "O programa não precisa esperar a operação de I/O terminar para continuar", "Menos uso de memória", "Maior compatibilidade"], correct: 1, explain: "I/O assíncrono permite que o programa continue executando outras tarefas enquanto aguarda operações lentas de disco ou rede." },
  ],
  operadores: [
    { id: 1, diff: "basica", text: "Qual é o resultado de 10 % 3?", opts: ["3", "1", "0", "10"], correct: 1, explain: "O operador módulo (%) retorna o resto da divisão. 10 ÷ 3 = 3 com resto 1.", wrongFeedback: { 0: "3 seria o quociente (resultado) da divisão inteira de 10 por 3. O módulo (%) retorna o RESTO, não o quociente.", 2: "0 seria o resto se 10 fosse divisível por 3 exatamente (como 9 % 3 = 0). Mas 10 ÷ 3 = 3 sobra 1.", 3: "10 é o próprio dividendo. O módulo retorna o resto, não o valor original." } },
    { id: 2, diff: "basica", text: "O operador '==' verifica o quê?", opts: ["Atribuição de valor", "Se dois valores são iguais", "Se um valor é maior", "Negação lógica"], correct: 1, explain: "== é operador relacional que compara dois valores e retorna verdadeiro se forem iguais.", wrongFeedback: { 0: "Atribuição de valor é feita com '=' (um sinal só). O '==' com dois sinais é comparação de igualdade — cuidado com essa diferença!", 2: "Para verificar se um valor é maior, usamos '>' ou '>='. O '==' apenas verifica igualdade.", 3: "Negação lógica é o operador '!' (ou 'not'). O '==' não nega — ele compara." } },
    { id: 3, diff: "basica", text: "Qual o resultado de: verdadeiro E falso?", opts: ["Verdadeiro", "Falso", "Indefinido", "Erro"], correct: 1, explain: "O operador lógico E (AND) retorna verdadeiro somente se AMBOS os operandos forem verdadeiros." },
    { id: 4, diff: "basica", text: "Qual operador representa a negação lógica?", opts: ["E", "OU", "NÃO", "XOR"], correct: 2, explain: "NÃO (NOT) inverte o valor lógico: NÃO verdadeiro = falso, NÃO falso = verdadeiro." },
    { id: 5, diff: "basica", text: "Qual o resultado de 2 ** 3 (potenciação)?", opts: ["6", "8", "9", "5"], correct: 1, explain: "2 ** 3 = 2³ = 2 × 2 × 2 = 8." },
    { id: 6, diff: "basica", text: "O operador '!=' significa:", opts: ["Maior que", "Igual a", "Diferente de", "Menor ou igual"], correct: 2, explain: "!= é o operador 'diferente de'. Retorna verdadeiro quando os valores comparados são diferentes." },
    { id: 7, diff: "basica", text: "Qual o resultado de: falso OU verdadeiro?", opts: ["Falso", "Verdadeiro", "Indefinido", "Erro"], correct: 1, explain: "O operador OU (OR) retorna verdadeiro se PELO MENOS UM dos operandos for verdadeiro." },
    { id: 8, diff: "basica", text: "Qual operador é usado para atribuir um valor a uma variável?", opts: ["==", "!=", "=", ">="], correct: 2, explain: "O operador = faz atribuição: x = 5 armazena o valor 5 na variável x. Diferente de == que compara." },
    { id: 9, diff: "intermediaria", text: "Qual é a precedência correta (maior para menor) entre operadores aritméticos?", opts: ["+ - * /", "* / + -", "/ * - +", "+ * / -"], correct: 1, explain: "Multiplicação e divisão têm precedência sobre adição e subtração, assim como na matemática." },
    { id: 10, diff: "intermediaria", text: "Qual o resultado de: 5 + 3 * 2?", opts: ["16", "11", "13", "10"], correct: 1, explain: "Multiplicação tem precedência: 3*2=6, depois 5+6=11. Parênteses mudariam isso: (5+3)*2=16." },
    { id: 11, diff: "intermediaria", text: "O que faz o operador de incremento (x++)?", opts: ["Multiplica x por 2", "Adiciona 1 ao valor de x", "Subtrai 1 de x", "Dobra x"], correct: 1, explain: "x++ (ou x+=1 ou x=x+1) adiciona 1 ao valor atual de x. É muito usado em contadores de loops." },
    { id: 12, diff: "intermediaria", text: "Qual o resultado de: NÃO (5 > 3)?", opts: ["Verdadeiro", "Falso", "5", "3"], correct: 1, explain: "5 > 3 é verdadeiro. NÃO verdadeiro = falso." },
    { id: 13, diff: "intermediaria", text: "O que é curto-circuito em operadores lógicos?", opts: ["Um erro elétrico", "Quando o resultado é determinado sem avaliar todos os operandos", "Uma operação mais rápida aritmeticamente", "Um tipo especial de loop"], correct: 1, explain: "Em A E B, se A for falso, B não é avaliado (resultado já é falso). Em A OU B, se A for verdadeiro, B é ignorado." },
    { id: 14, diff: "intermediaria", text: "Qual o resultado de: (10 > 5) E (3 < 1)?", opts: ["Verdadeiro", "Falso", "10", "Erro"], correct: 1, explain: "10 > 5 é verdadeiro, mas 3 < 1 é falso. Verdadeiro E Falso = Falso." },
    { id: 15, diff: "intermediaria", text: "O que faz x += 5?", opts: ["Compara x com 5", "É equivalente a x = x + 5", "Cria uma nova variável", "Apaga x"], correct: 1, explain: "Operadores de atribuição compostos combinam operação e atribuição: x += 5 é atalho para x = x + 5." },
    { id: 16, diff: "intermediaria", text: "Qual o valor de x após: x = 10; x -= 3; x *= 2?", opts: ["14", "17", "20", "7"], correct: 0, explain: "x=10, depois x=10-3=7, depois x=7*2=14." },
    { id: 17, diff: "avancada", text: "O que é o operador ternário?", opts: ["Um operador com três variáveis", "Uma forma compacta de if-else: condição ? valor_true : valor_false", "Um operador de três bits", "Uma função matemática"], correct: 1, explain: "O operador ternário avalia uma condição e retorna um de dois valores. Ex: x > 0 ? 'positivo' : 'negativo'." },
    { id: 18, diff: "avancada", text: "O que faz o operador bit a bit AND (&)?", opts: ["Soma dois números", "Compara bits correspondentes: 1 apenas se ambos forem 1", "Inverte todos os bits", "Desloca bits à esquerda"], correct: 1, explain: "AND bit a bit (&) opera sobre cada par de bits. 1010 & 1100 = 1000. Útil para máscaras de bits." },
    { id: 19, diff: "avancada", text: "Qual o resultado de 5 << 1 (deslocamento de bits à esquerda)?", opts: ["5", "10", "2", "25"], correct: 1, explain: "Deslocar bits à esquerda por 1 equivale a multiplicar por 2. 5 em binário é 101; deslocado fica 1010 = 10." },
    { id: 20, diff: "avancada", text: "O que é o operador XOR (OU exclusivo)?", opts: ["Verdadeiro se ambos forem verdadeiros", "Verdadeiro se apenas um dos operandos for verdadeiro", "Equivalente ao AND", "Negação do OR"], correct: 1, explain: "XOR retorna verdadeiro apenas quando os operandos são diferentes: V XOR F = V, V XOR V = F, F XOR F = F." },
    { id: 21, diff: "avancada", text: "O operador de coalescência nula (??) faz o quê?", opts: ["Soma nulos", "Retorna o operando direito se o esquerdo for nulo/indefinido", "Verifica se dois valores são nulos", "Converte nulo para zero"], correct: 1, explain: "?? (nullish coalescing) retorna o valor da direita apenas se o da esquerda for null ou undefined. Ex: x ?? 'padrão'." },
  ],
  condicionais: [
    { id: 1, diff: "basica", text: "O que faz uma estrutura SE-ENTÃO (if-then)?", opts: ["Repete um bloco de código", "Executa um bloco apenas se uma condição for verdadeira", "Define uma função", "Declara uma variável"], correct: 1, explain: "A estrutura condicional SE verifica uma condição e executa o bloco somente se ela for verdadeira." },
    { id: 2, diff: "basica", text: "Com nota = 5, o que imprime: SE nota >= 7: 'Aprovado' SENÃO: 'Reprovado'?", opts: ["Aprovado", "Reprovado", "Nada", "Erro"], correct: 1, explain: "5 >= 7 é falso, então o bloco SENÃO executa, imprimindo 'Reprovado'." },
    { id: 3, diff: "basica", text: "O que é o bloco SENÃO (else)?", opts: ["Executa sempre", "Executa quando a condição do SE é falsa", "Repete o SE", "Cria uma nova condição"], correct: 1, explain: "O bloco else é opcional e executa apenas quando a condição do if é falsa — é o caminho alternativo." },
    { id: 4, diff: "basica", text: "Uma estrutura condicional avalia o que para decidir o fluxo?", opts: ["Um número", "Uma condição (expressão booleana)", "Uma string", "Um loop"], correct: 1, explain: "Condicionais avaliam expressões booleanas (verdadeiro/falso) para decidir qual caminho do código executar." },
    { id: 5, diff: "basica", text: "Qual estrutura verifica múltiplas condições em sequência?", opts: ["Loop while", "SE-SENÃO SE (if-else if)", "Função", "Variável"], correct: 1, explain: "if-else if permite verificar várias condições em cadeia, executando o primeiro bloco cuja condição seja verdadeira." },
    { id: 6, diff: "basica", text: "O que acontece se nenhuma condição de uma cadeia if-else if for verdadeira e não houver else?", opts: ["Erro no programa", "Nenhum bloco é executado", "O primeiro bloco executa", "O último bloco executa"], correct: 1, explain: "Se nenhuma condição for verdadeira e não houver else, o programa simplesmente pula toda a estrutura condicional." },
    { id: 7, diff: "basica", text: "Condicionais aninhadas são:", opts: ["Proibidas", "Condicionais dentro de outras condicionais", "Condicionais sem else", "Loops com condição"], correct: 1, explain: "Condicionais aninhadas são estruturas if dentro de outras estruturas if, permitindo verificações mais complexas." },
    { id: 8, diff: "basica", text: "Com x = 10, qual bloco executa: SE x > 5 ENTÃO 'A' SENÃO 'B'?", opts: ["B", "A", "Nenhum", "Ambos"], correct: 1, explain: "10 > 5 é verdadeiro, então o bloco ENTÃO executa, imprimindo 'A'." },
    { id: 9, diff: "intermediaria", text: "Qual estrutura é mais adequada para múltiplas condições exclusivas com valor específico?", opts: ["Vários SE independentes", "SE-SENÃO SE-SENÃO encadeado", "Switch/Case", "Loop for"], correct: 2, explain: "Switch/Case é ideal quando comparamos uma variável com múltiplos valores fixos — mais legível que vários if-else." },
    { id: 10, diff: "intermediaria", text: "SE (x > 0 E y > 0), o que é necessário para o bloco executar?", opts: ["Apenas x > 0", "Apenas y > 0", "Ambos x > 0 e y > 0", "Nenhum dos dois"], correct: 2, explain: "Com operador E (AND), ambas as condições devem ser verdadeiras para o bloco executar." },
    { id: 11, diff: "intermediaria", text: "Qual o problema de usar = em vez de == em uma condição?", opts: ["Nenhum problema", "Atribui valor em vez de comparar, geralmente sempre verdadeiro", "Causa erro de sintaxe sempre", "Compara endereços de memória"], correct: 1, explain: "if(x = 5) atribui 5 a x (resultado não-zero = verdadeiro) em vez de comparar. Bug clássico e difícil de detectar." },
    { id: 12, diff: "intermediaria", text: "Com nota = 8.5, o que exibe: SE nota>=9: 'A'; SENÃO SE nota>=7: 'B'; SENÃO: 'C'?", opts: ["A", "B", "C", "Nenhuma"], correct: 1, explain: "8.5 >= 9 é falso; 8.5 >= 7 é verdadeiro → imprime 'B'. A primeira condição verdadeira vence." },
    { id: 13, diff: "intermediaria", text: "O que é uma expressão ternária como alternativa a if-else?", opts: ["Um loop compacto", "Uma forma curta de escrever if-else em uma linha", "Um tipo de switch", "Uma função anônima"], correct: 1, explain: "resultado = (condição) ? valor_se_true : valor_se_false. Compacto mas deve ser usado com moderação." },
    { id: 14, diff: "intermediaria", text: "SE (x > 0 OU y > 0), o que basta para o bloco executar?", opts: ["Ambos positivos", "Apenas um deles positivo já basta", "Nenhum positivo", "Apenas x positivo"], correct: 1, explain: "Com OU (OR), basta que UMA das condições seja verdadeira para o bloco executar." },
    { id: 15, diff: "intermediaria", text: "Qual a diferença entre SEs separados e SE-SENÃO SE encadeados?", opts: ["Nenhuma", "SE separados verificam todas as condições; encadeados param na primeira verdadeira", "Encadeados são mais lentos", "SE separados são mais legíveis"], correct: 1, explain: "SE-SENÃO SE para na primeira condição verdadeira. SEs independentes verificam todos, podendo executar múltiplos blocos." },
    { id: 16, diff: "intermediaria", text: "Um switch/case sem 'break' entre os casos causa o quê?", opts: ["Erro de compilação", "Fall-through: executa os casos seguintes também", "Ignora os outros casos", "Reinicia do primeiro caso"], correct: 1, explain: "Sem break, o switch 'cai' (fall-through) para o próximo case, executando-o mesmo que sua condição não corresponda." },
    { id: 17, diff: "avancada", text: "O que são guard clauses (cláusulas de guarda)?", opts: ["Proteção de memória", "Condicionais antecipadas que retornam cedo para reduzir aninhamento", "Verificações de segurança do sistema", "Tipos de exceções"], correct: 1, explain: "Guard clauses retornam early quando condições inválidas são detectadas, evitando profundo aninhamento de if-else." },
    { id: 18, diff: "avancada", text: "O que é correspondência de padrões (pattern matching) em linguagens modernas?", opts: ["Busca com regex", "Uma forma avançada de switch que desestrutura e verifica estruturas complexas", "Comparação de strings", "Um tipo de loop"], correct: 1, explain: "Pattern matching (como em Rust, Haskell, Python 3.10+) permite verificar condições e desestruturar dados em uma única expressão." },
    { id: 19, diff: "avancada", text: "O que é avaliação de curto-circuito em condicionais compostas?", opts: ["Um erro de execução", "Parar de avaliar operandos assim que o resultado é determinado", "Executar todos os casos", "Uma otimização de compilador apenas"], correct: 1, explain: "Em 'A E B', se A é falso, B não é avaliado. Em 'A OU B', se A é verdadeiro, B é pulado. Evita erros e melhora desempenho." },
    { id: 20, diff: "avancada", text: "Qual o risco de condicionais com muitos níveis de aninhamento?", opts: ["Código mais rápido", "Código difícil de ler, testar e manter — 'pyramid of doom'", "Maior uso de variáveis", "Erros de compilação"], correct: 1, explain: "Aninhamento profundo ('pyramid of doom') reduz legibilidade drasticamente. Soluções: guard clauses, funções auxiliares ou pattern matching." },
    { id: 21, diff: "avancada", text: "Como condicionais se relacionam com a cobertura de testes?", opts: ["Não têm relação", "Cada ramificação (branch) deve ser testada para 100% de cobertura", "Apenas o caminho feliz precisa ser testado", "Condicionais não precisam de testes"], correct: 1, explain: "Boa cobertura de testes requer que cada branch (caminho de if/else) seja exercitado por pelo menos um teste." },
  ],
  repeticao: [
    { id: 1, diff: "basica", text: "Para que serve um laço de repetição (loop)?", opts: ["Declarar variáveis", "Executar um bloco de código múltiplas vezes", "Definir funções", "Comparar valores"], correct: 1, explain: "Loops repetem um bloco de código sem precisar escrevê-lo várias vezes — essencial para automatização." },
    { id: 2, diff: "basica", text: "Um loop PARA i de 1 até 5 executa quantas vezes?", opts: ["4", "5", "6", "Infinitas"], correct: 1, explain: "O loop executa para i=1, 2, 3, 4, 5 — portanto 5 vezes." },
    { id: 3, diff: "basica", text: "Qual a diferença entre ENQUANTO e FAÇA-ENQUANTO?", opts: ["Nenhuma", "FAÇA-ENQUANTO executa o bloco pelo menos uma vez", "ENQUANTO é mais rápido", "FAÇA-ENQUANTO não aceita condições"], correct: 1, explain: "FAÇA-ENQUANTO (do-while) testa a condição após executar o bloco, garantindo pelo menos uma execução." },
    { id: 4, diff: "basica", text: "O que é a variável de controle de um loop?", opts: ["Uma constante", "A variável que controla quantas vezes o loop executa", "Uma variável global", "O resultado do loop"], correct: 1, explain: "A variável de controle (como 'i' no for) é incrementada a cada iteração e determina quando o loop termina." },
    { id: 5, diff: "basica", text: "Qual loop é mais adequado quando não sabemos quantas vezes repetir?", opts: ["for", "while", "do-while", "repeat"], correct: 1, explain: "O while é ideal quando a repetição depende de uma condição que pode mudar de forma imprevisível, não de um contador fixo." },
    { id: 6, diff: "basica", text: "O que acontece em um loop infinito?", opts: ["O loop executa 0 vezes", "O programa fica preso executando o loop para sempre", "O loop executa 1 vez", "O programa reinicia"], correct: 1, explain: "Loop infinito ocorre quando a condição de parada nunca é satisfeita. O programa trava até ser forçado a encerrar." },
    { id: 7, diff: "basica", text: "O que faz a instrução 'break' dentro de um loop?", opts: ["Pausa o loop temporariamente", "Encerra o loop imediatamente", "Pula para a próxima iteração", "Reinicia o loop"], correct: 1, explain: "break interrompe o loop imediatamente, independente da condição. O programa continua após o loop." },
    { id: 8, diff: "basica", text: "O que faz a instrução 'continue' dentro de um loop?", opts: ["Encerra o loop", "Pula o restante da iteração atual e vai para a próxima", "Reinicia do zero", "Pausa o loop"], correct: 1, explain: "continue interrompe a iteração atual e avança para a próxima, sem encerrar o loop." },
    { id: 9, diff: "intermediaria", text: "Qual o resultado: soma=0; PARA i de 1 até 4: soma = soma + i?", opts: ["4", "10", "6", "0"], correct: 1, explain: "soma = 0+1+2+3+4 = 10. O loop acumula 1+2+3+4." },
    { id: 10, diff: "intermediaria", text: "O que são loops aninhados?", opts: ["Loops com break", "Loops dentro de outros loops", "Loops com continue", "Loops infinitos controlados"], correct: 1, explain: "Loops aninhados têm um loop dentro do corpo de outro. Para cada iteração do externo, o interno executa completamente." },
    { id: 11, diff: "intermediaria", text: "Quantas vezes o bloco interno executa: PARA i de 1 a 3: PARA j de 1 a 3?", opts: ["3", "6", "9", "1"], correct: 2, explain: "O loop externo executa 3 vezes. Para cada vez, o interno executa 3 vezes. Total: 3 × 3 = 9 execuções." },
    { id: 12, diff: "intermediaria", text: "Qual loop garante execução pelo menos uma vez?", opts: ["for", "while", "do-while", "foreach"], correct: 2, explain: "do-while testa a condição APÓS a primeira execução, garantindo que o bloco execute pelo menos uma vez." },
    { id: 13, diff: "intermediaria", text: "O que é o passo (step) em um loop for?", opts: ["O valor inicial", "O incremento aplicado à variável de controle a cada iteração", "A condição de parada", "O número de iterações"], correct: 1, explain: "O passo define quanto a variável de controle muda a cada iteração. Pode ser 1, 2, -1, etc." },
    { id: 14, diff: "intermediaria", text: "PARA i de 10 até 1, passo -1: qual o valor de i na última iteração?", opts: ["10", "1", "0", "-1"], correct: 1, explain: "O loop conta de 10 até 1 com passo -1. A última iteração tem i=1, depois i seria 0, que não satisfaz i>=1." },
    { id: 15, diff: "intermediaria", text: "O que é um loop foreach?", opts: ["Um loop infinito", "Um loop que itera sobre cada elemento de uma coleção", "Um loop com passo fixo", "Um loop com condição dupla"], correct: 1, explain: "foreach itera automaticamente sobre cada elemento de uma coleção (lista, array), sem precisar de índice numérico." },
    { id: 16, diff: "intermediaria", text: "Qual a saída: i=1; ENQUANTO i<=3: imprima i; i=i+1?", opts: ["1 2 3 4", "1 2 3", "1 2", "Loop infinito"], correct: 1, explain: "i assume valores 1, 2, 3. Quando i=4, 4<=3 é falso e o loop termina. Saída: 1 2 3." },
    { id: 17, diff: "avancada", text: "O que é uma compreensão de lista (list comprehension)?", opts: ["Uma lista de comentários", "Uma sintaxe compacta para criar listas com base em loops e condições", "Um tipo de loop infinito", "Uma função recursiva"], correct: 1, explain: "List comprehension (ex: [x*2 for x in range(5)]) cria listas de forma concisa combinando loop e expressão em uma linha." },
    { id: 18, diff: "avancada", text: "O que é um iterador (iterator)?", opts: ["Um tipo de variável", "Um objeto que permite percorrer uma coleção um elemento por vez", "Um tipo de função", "Um loop especial"], correct: 1, explain: "Iteradores implementam o protocolo de iteração, permitindo percorrer coleções sequencialmente com lazy evaluation." },
    { id: 19, diff: "avancada", text: "Qual a vantagem de generators em vez de listas em loops?", opts: ["Código mais rápido sempre", "Menor uso de memória — geram valores sob demanda", "Maior compatibilidade", "Sintaxe mais simples"], correct: 1, explain: "Generators produzem valores um por vez (lazy), não armazenam tudo na memória. Ideal para sequências grandes ou infinitas." },
    { id: 20, diff: "avancada", text: "O que é recursão de cauda (tail recursion)?", opts: ["Recursão com muitos níveis", "Quando a chamada recursiva é a última operação da função, permitindo otimização", "Uma recursão sem caso base", "Recursão mútua"], correct: 1, explain: "Tail recursion permite que compiladores otimizem a chamada recursiva reutilizando o mesmo frame de pilha, evitando stack overflow." },
    { id: 21, diff: "avancada", text: "O que é paralelismo em loops (loop parallelism)?", opts: ["Dois loops aninhados", "Executar iterações do loop simultaneamente em múltiplos núcleos", "Um loop com dois contadores", "Loops com break e continue juntos"], correct: 1, explain: "Loop parallelism distribui iterações independentes entre múltiplos threads/núcleos, reduzindo tempo em operações intensivas." },
  ],
  funcoes: [
    { id: 1, diff: "basica", text: "O que é uma função em programação?", opts: ["Um tipo de variável", "Um bloco de código reutilizável com nome próprio", "Um operador matemático", "Uma estrutura de repetição"], correct: 1, explain: "Uma função é um bloco de código nomeado que pode ser chamado várias vezes, promovendo reutilização e organização." },
    { id: 2, diff: "basica", text: "O que são parâmetros de uma função?", opts: ["Erros da função", "Valores passados para a função ao chamá-la", "O resultado da função", "Variáveis globais"], correct: 1, explain: "Parâmetros são variáveis que recebem valores quando a função é chamada, permitindo comportamento flexível." },
    { id: 3, diff: "basica", text: "O que faz a instrução 'return' em uma função?", opts: ["Repete a função", "Encerra a função e opcionalmente retorna um valor", "Imprime um valor", "Declara uma variável"], correct: 1, explain: "return encerra a execução da função e pode enviar um valor de volta para quem chamou a função." },
    { id: 4, diff: "basica", text: "Para que serve chamar (invocar) uma função?", opts: ["Declarar a função", "Executar o bloco de código da função", "Apagar a função", "Copiar a função"], correct: 1, explain: "Invocar/chamar uma função executa o código dentro dela. A declaração define o que fazer; a chamada faz isso acontecer." },
    { id: 5, diff: "basica", text: "Uma função pode retornar um valor?", opts: ["Nunca", "Sim, usando return", "Apenas valores numéricos", "Apenas strings"], correct: 1, explain: "Funções podem retornar qualquer tipo de valor com return. Funções sem return (void/None) não retornam nada." },
    { id: 6, diff: "basica", text: "Qual a vantagem principal de usar funções?", opts: ["Código mais lento", "Reutilização de código e organização", "Uso de mais memória", "Código mais difícil de ler"], correct: 1, explain: "Funções evitam repetição de código (DRY: Don't Repeat Yourself) e organizam o programa em partes lógicas menores." },
    { id: 7, diff: "basica", text: "O que é a assinatura de uma função?", opts: ["A documentação da função", "O nome da função junto com seus parâmetros e tipo de retorno", "O corpo da função", "Os erros da função"], correct: 1, explain: "A assinatura identifica a função: seu nome, a lista de parâmetros (tipos e nomes) e o tipo do valor retornado." },
    { id: 8, diff: "basica", text: "Uma função sem parâmetros:", opts: ["É inválida", "Pode existir e realiza sempre a mesma operação fixa", "Sempre retorna zero", "Não pode ter return"], correct: 1, explain: "Funções sem parâmetros são válidas. Ex: uma função que sempre retorna a data/hora atual ou imprime um cabeçalho fixo." },
    { id: 9, diff: "intermediaria", text: "Qual a diferença entre parâmetro e argumento?", opts: ["São a mesma coisa", "Parâmetro é na definição; argumento é o valor passado na chamada", "Argumento é na definição; parâmetro é na chamada", "Parâmetro é global; argumento é local"], correct: 1, explain: "Parâmetro: variável na declaração da função (def soma(a, b)). Argumento: valor concreto passado na chamada (soma(3, 5))." },
    { id: 10, diff: "intermediaria", text: "O que é uma função void (ou sem retorno)?", opts: ["Uma função sem parâmetros", "Uma função que não retorna valor algum", "Uma função vazia sem código", "Uma função que retorna zero"], correct: 1, explain: "Funções void executam ações (como imprimir ou modificar estado) mas não retornam valor para quem as chamou." },
    { id: 11, diff: "intermediaria", text: "O que é escopo local de uma variável em uma função?", opts: ["A variável existe em todo o programa", "A variável existe apenas dentro da função onde foi declarada", "A variável é constante", "A variável é compartilhada entre funções"], correct: 1, explain: "Variáveis locais existem apenas durante a execução da função. Após o retorno, elas são destruídas." },
    { id: 12, diff: "intermediaria", text: "O que é sobrecarga de função (overloading)?", opts: ["Chamar uma função muitas vezes", "Ter múltiplas funções com o mesmo nome mas parâmetros diferentes", "Uma função que chama outra", "Uma função com muitos parâmetros"], correct: 1, explain: "Overloading permite várias funções com o mesmo nome mas assinaturas diferentes. O compilador escolhe a correta pelos argumentos." },
    { id: 13, diff: "intermediaria", text: "O que são funções de alta ordem (higher-order functions)?", opts: ["Funções matemáticas complexas", "Funções que recebem ou retornam outras funções", "Funções recursivas", "Funções com muitos parâmetros"], correct: 1, explain: "Higher-order functions tratam funções como valores: podem recebê-las como parâmetro (map, filter) ou retorná-las (closures)." },
    { id: 14, diff: "intermediaria", text: "O que é uma função recursiva?", opts: ["Uma função muito longa", "Uma função que chama a si mesma", "Uma função sem return", "Uma função aninhada"], correct: 1, explain: "Recursão é quando uma função chama a si mesma para resolver um problema menor, até atingir o caso base." },
    { id: 15, diff: "intermediaria", text: "Calcule: fatorial(n): SE n<=1: retorne 1; SENÃO: retorne n * fatorial(n-1). Qual é fatorial(4)?", opts: ["4", "16", "24", "12"], correct: 2, explain: "fatorial(4) = 4 × fatorial(3) = 4 × 3 × 2 × 1 = 24." },
    { id: 16, diff: "intermediaria", text: "O que são parâmetros padrão (default parameters)?", opts: ["Parâmetros obrigatórios", "Parâmetros com valor pré-definido usado quando não fornecido na chamada", "O primeiro parâmetro da função", "Parâmetros numéricos"], correct: 1, explain: "Parâmetros padrão têm valor pré-definido. Ex: def saudar(nome, msg='Olá'). Chamar saudar('Ana') usa msg='Olá' automaticamente." },
    { id: 17, diff: "avancada", text: "O que é uma função lambda (anônima)?", opts: ["Uma função sem corpo", "Uma função pequena sem nome, definida inline", "Uma função de biblioteca", "Uma função com um parâmetro"], correct: 1, explain: "Lambdas são funções anônimas de uma expressão. Ex: quadrado = lambda x: x**2. Úteis como argumentos de funções de alta ordem." },
    { id: 18, diff: "avancada", text: "O que é uma closure?", opts: ["Um erro de função", "Uma função que captura variáveis do escopo onde foi criada", "Uma função sem parâmetros", "Uma função recursiva"], correct: 1, explain: "Closure é uma função que 'lembra' variáveis do escopo externo onde foi definida, mesmo após esse escopo ter encerrado." },
    { id: 19, diff: "avancada", text: "O que é memoização em funções recursivas?", opts: ["Documentar a função", "Armazenar resultados já calculados para evitar recálculos", "Um tipo de recursão", "Otimização de parâmetros"], correct: 1, explain: "Memoização guarda resultados de chamadas anteriores. fib(10) chamada duas vezes: na segunda, o resultado é recuperado em O(1)." },
    { id: 20, diff: "avancada", text: "O que é o princípio da responsabilidade única aplicado a funções?", opts: ["Funções com um parâmetro", "Cada função deve fazer apenas uma coisa bem definida", "Funções sem efeitos colaterais", "Funções puras"], correct: 1, explain: "SRP (Single Responsibility Principle): funções devem ter uma única responsabilidade clara. Facilita testes, reutilização e manutenção." },
    { id: 21, diff: "avancada", text: "O que são efeitos colaterais (side effects) em funções?", opts: ["Erros de execução", "Modificações de estado externo à função (variáveis globais, I/O, banco de dados)", "Retornos múltiplos", "Parâmetros extras"], correct: 1, explain: "Side effects são mudanças observáveis fora do escopo da função. Funções puras evitam side effects, facilitando testes e raciocínio." },
  ],
  vetores: [
    { id: 1, diff: "basica", text: "O que é um vetor (array)?", opts: ["Um tipo de loop", "Uma coleção de elementos do mesmo tipo em sequência", "Uma função especial", "Um operador lógico"], correct: 1, explain: "Um vetor armazena múltiplos valores do mesmo tipo em posições indexadas sequencialmente." },
    { id: 2, diff: "basica", text: "Se um vetor tem 5 elementos, qual é o índice do último (base zero)?", opts: ["5", "4", "1", "0"], correct: 1, explain: "Em indexação base-zero (a mais comum), um vetor de 5 elementos tem índices de 0 a 4. O último é 4." },
    { id: 3, diff: "basica", text: "O que é uma matriz?", opts: ["Um vetor muito grande", "Um vetor bidimensional (linhas e colunas)", "Um tipo de função", "Um operador especial"], correct: 1, explain: "Matriz é um array bidimensional organizado em linhas e colunas. Ex: uma tabela 3×4 tem 3 linhas e 4 colunas." },
    { id: 4, diff: "basica", text: "Como acessamos o elemento na posição 3 de um vetor 'v' (base zero)?", opts: ["v(3)", "v[2]", "v{3}", "v.3"], correct: 1, explain: "Em indexação base-zero, a posição 3 (terceiro elemento) está no índice 2: v[2]. A sintaxe usa colchetes." },
    { id: 5, diff: "basica", text: "O que acontece ao tentar acessar um índice fora dos limites do vetor?", opts: ["Retorna zero", "Retorna nulo", "Gera erro (index out of bounds)", "Retorna o último elemento"], correct: 2, explain: "Acessar um índice inválido gera erro de 'índice fora dos limites'. É uma das exceções mais comuns em programação." },
    { id: 6, diff: "basica", text: "Em vetores tipados (C, Java), os elementos devem ser:", opts: ["Misturados", "Do mesmo tipo", "Apenas numéricos", "Apenas textos"], correct: 1, explain: "Em linguagens tipadas como C e Java, vetores armazenam apenas um tipo. Em Python/JS, listas podem misturar tipos." },
    { id: 7, diff: "basica", text: "O que é o tamanho (length) de um vetor?", opts: ["O maior valor armazenado", "A quantidade de elementos no vetor", "O índice do último elemento", "O tipo dos elementos"], correct: 1, explain: "O tamanho/comprimento do vetor é o número total de elementos. Para um vetor de 5 elementos, length = 5." },
    { id: 8, diff: "basica", text: "Como percorrer todos os elementos de um vetor eficientemente?", opts: ["Manualmente, um por um", "Usando um loop que itera pelos índices ou elementos", "Usando condicionais", "Usando funções matemáticas"], correct: 1, explain: "Loops são a forma natural de percorrer vetores: for i in range(len(v)) ou for elemento in v (foreach)." },
    { id: 9, diff: "intermediaria", text: "Qual é a complexidade de busca em um vetor não ordenado?", opts: ["O(1)", "O(log n)", "O(n)", "O(n²)"], correct: 2, explain: "Busca linear em vetor não ordenado: no pior caso percorremos todos os n elementos — complexidade O(n)." },
    { id: 10, diff: "intermediaria", text: "Como copiar um vetor sem que alterações na cópia afetem o original?", opts: ["b = a", "b = a.copy() ou b = a[:]", "b = &a", "b = *a"], correct: 1, explain: "b = a cria outra referência ao mesmo objeto. Para uma cópia independente use .copy(), list(), ou fatiamento [:]." },
    { id: 11, diff: "intermediaria", text: "O que é um vetor dinâmico (como ArrayList ou list)?", opts: ["Um vetor que cresce/encolhe automaticamente conforme necessário", "Um vetor muito rápido", "Um vetor bidimensional", "Um vetor ordenado"], correct: 0, explain: "Vetores dinâmicos ajustam seu tamanho automaticamente. Diferente de arrays estáticos onde o tamanho é fixo na criação." },
    { id: 12, diff: "intermediaria", text: "Qual algoritmo de ordenação simples compara elementos adjacentes repetidamente?", opts: ["Merge Sort", "Quick Sort", "Bubble Sort", "Heap Sort"], correct: 2, explain: "Bubble Sort compara pares adjacentes e os troca se estiverem fora de ordem, 'borbulhando' o maior para o final." },
    { id: 13, diff: "intermediaria", text: "Em uma matriz 3×4, quantos elementos existem no total?", opts: ["7", "12", "3", "4"], correct: 1, explain: "3 linhas × 4 colunas = 12 elementos no total." },
    { id: 14, diff: "intermediaria", text: "Como acessar o elemento da linha 2, coluna 3 em uma matriz m (base zero)?", opts: ["m[2][3]", "m[1][2]", "m[2,3]", "m(2)(3)"], correct: 1, explain: "Em base-zero: linha 2 = índice 1, coluna 3 = índice 2. Acesso: m[1][2] com colchetes duplos." },
    { id: 15, diff: "intermediaria", text: "O que é fatiamento (slicing) de vetores?", opts: ["Dividir o vetor ao meio", "Extrair uma subparte do vetor por índices de início e fim", "Ordenar o vetor", "Remover duplicatas"], correct: 1, explain: "Slicing extrai uma porção: v[1:4] retorna elementos dos índices 1, 2, 3 (fim é exclusivo). Muito poderoso em Python." },
    { id: 16, diff: "intermediaria", text: "Qual operação adiciona um elemento ao final de um vetor dinâmico?", opts: ["insert()", "add_front()", "append() ou push()", "concat()"], correct: 2, explain: "append() em Python, push() em JavaScript — adicionam ao final. Inserir no meio é mais custoso (O(n))." },
    { id: 17, diff: "avancada", text: "O que é complexidade de espaço em algoritmos com vetores?", opts: ["O tempo de execução", "A memória extra usada além do vetor de entrada", "O tamanho do vetor", "A velocidade de acesso"], correct: 1, explain: "Complexidade de espaço mede memória adicional. Um algoritmo in-place usa O(1) extra; criar um novo vetor usa O(n)." },
    { id: 18, diff: "avancada", text: "O que é um vetor esparso (sparse array)?", opts: ["Um vetor sem elementos", "Um vetor onde a maioria dos elementos é zero/nulo, armazenado eficientemente", "Um vetor ordenado", "Um vetor com um único elemento"], correct: 1, explain: "Vetores esparsos têm muitos zeros/nulos. Armazená-los eficientemente (apenas os não-nulos) economiza memória em grandes matrizes." },
    { id: 19, diff: "avancada", text: "O que é localidade de cache e como vetores se beneficiam?", opts: ["Vetores são lentos por isso", "Vetores contíguos na memória permitem que a CPU pré-carregue elementos no cache", "Cache só beneficia dicionários", "Não há relação"], correct: 1, explain: "Vetores armazenam elementos contíguos na memória. A CPU carrega blocos inteiros no cache, fazendo acesso sequencial muito eficiente." },
    { id: 20, diff: "avancada", text: "Qual a complexidade de inserção no meio de um array estático?", opts: ["O(1)", "O(log n)", "O(n)", "O(n²)"], correct: 2, explain: "Inserir no meio requer deslocar todos os elementos posteriores uma posição — O(n) no pior caso." },
    { id: 21, diff: "avancada", text: "Arrays têm acesso a qualquer posição com qual complexidade?", opts: ["O(n)", "O(log n)", "O(n²)", "O(1)"], correct: 3, explain: "Arrays têm acesso direto O(1) por índice porque sabem o endereço de qualquer elemento: endereço_base + índice × tamanho_elemento." },
  ],
};
